mapper.select:
select reservation_id, space_name, user_id, user_name, user_phone,
       reserve_date, start_time, end_time, reservation_purpose,
       reservation_status, reject_reason, approver_id, approve_time,
       create_time, update_time, remark
from venue_booking

    and reservation_id = #{id}
    and space_name like concat('%', #{spaceName}, '%')
    and user_id = #{userId}
    and user_name like concat('%', #{userName}, '%')
    and user_phone = #{userPhone}
    and reserve_date = #{reserveDate}
    and reservation_status = #{status}

order by create_time desc

mapper.update:
update venue_booking
space_name = #{spaceName}, user_id = #{userId}, user_name = #{userName}, user_phone = #{userPhone}, reserve_date = #{reserveDate}, start_time = #{startTime}, end_time = #{endTime}, reservation_purpose = #{reservationPurpose}, reservation_status = #{status}, reject_reason = #{rejectReason}, approver_id = #{approverId}, approve_time = #{approveTime}, update_time = #{updateTime}, remark = #{remark},
where reservation_id = #{id}
